const response = $input.first().json;
let data;
try {
  const content = response.message?.content || response.content || response.choices?.[0]?.message?.content || JSON.stringify(response);
  try { data = typeof content === 'object' ? content : JSON.parse(content); }
  catch { const m = content.match(/```json?\n?([\s\S]*?)\n?```/); if(m){data=JSON.parse(m[1])}else{data=JSON.parse(content.match(/\{[\s\S]*\}/)[0])} }
} catch (e) { return [{json:{error:'Parsing échoué: '+e.message}}]; }
const politique = data.politique || data.actualites || [];
const tech = data.tech || [];
const sortByViral = (arr) => (Array.isArray(arr)?arr:[]).sort((a,b)=>({'fort':3,'moyen':2,'faible':1}[b.potentiel_viral]||0)-({'fort':3,'moyen':2,'faible':1}[a.potentiel_viral]||0));
return [{json:{ politique: sortByViral(politique), tech: sortByViral(tech), date_generation: new Date().toISOString().split('T')[0], date_publication: new Date(Date.now()+86400000).toISOString().split('T')[0] }}];

const response = $input.first().json;
const prev = $('📊 Parser les actus').first().json;
let posts;

try {
  let c = response.response || response.text || response.output || JSON.stringify(response);
  if (typeof c === 'object') { posts = c; }
  else {
    // Nettoyer les blocs markdown
    const mdMatch = c.match(/```json?\n?([\s\S]*?)\n?```/);
    if (mdMatch) c = mdMatch[1];

    // Parser robuste : nettoyer caractère par caractère les \n dans les strings JSON
    let cleaned = '';
    let inString = false;
    let escaped = false;

    for (let i = 0; i < c.length; i++) {
      const ch = c[i];

      if (escaped) {
        cleaned += ch;
        escaped = false;
        continue;
      }

      if (ch === '\\') {
        escaped = true;
        cleaned += ch;
        continue;
      }

      if (ch === '"') {
        inString = !inString;
        cleaned += ch;
        continue;
      }

      if (inString) {
        // Remplacer les vrais sauts de ligne par \n dans les strings
        if (ch === '\n') { cleaned += '\\n'; continue; }
        if (ch === '\r') { cleaned += '\\r'; continue; }
        if (ch === '\t') { cleaned += '\\t'; continue; }
      }

      cleaned += ch;
    }

    // Extraire le JSON objet
    const braceStart = cleaned.indexOf('{');
    const braceEnd = cleaned.lastIndexOf('}');
    if (braceStart === -1 || braceEnd === -1) throw new Error('Pas de JSON trouvé');

    const jsonStr = cleaned.substring(braceStart, braceEnd + 1);

    try {
      posts = JSON.parse(jsonStr);
    } catch (e2) {
      // Dernier recours : essayer de parser le texte brut
      const rawBrace = c.substring(c.indexOf('{'), c.lastIndexOf('}') + 1);
      // Remplacer tous les \n dans les strings manuellement
      let fixedJson = '';
      let inStr = false;
      let esc = false;
      for (let i = 0; i < rawBrace.length; i++) {
        const ch = rawBrace[i];
        if (esc) { fixedJson += ch; esc = false; continue; }
        if (ch === '\\') { esc = true; fixedJson += ch; continue; }
        if (ch === '"') { inStr = !inStr; fixedJson += ch; continue; }
        if (inStr && ch === '\n') { fixedJson += '\\n'; continue; }
        if (inStr && ch === '\r') { continue; }
        fixedJson += ch;
      }
      posts = JSON.parse(fixedJson);
    }
  }
} catch(e) {
  return [{json:{
    Titre: 'ERREUR PARSING',
    Type: 'actu',
    Contenu: 'Erreur: ' + e.message + '\n\nRéponse brute (début): ' + String(response.response || response.text || '').substring(0, 500),
    'Date Publication': prev.date_publication,
    'Heure Suggérée': '',
    Statut: 'Rejeté',
    'Source Actu': '',
    'Date Génération': prev.date_generation,
    'Publié': false,
    image_titre: '',
    image_sous_titre: '',
    image_icone: ''
  }}];
}

const arr = posts.posts || posts;
const items = Array.isArray(arr) ? arr : [arr];

return items.map(p => {
  // Reconstituer le contenu proprement
  let contenu = p.contenu || '';
  // S'assurer que les \n sont de vrais sauts de ligne
  contenu = contenu.replace(/\\n/g, '\n');
  // Ajouter les hashtags à la fin
  const hashtags = p.hashtags || '';
  if (hashtags && !contenu.includes(hashtags)) {
    contenu = contenu + '\n\n' + hashtags;
  }

  return {
    json: {
      Titre: p.titre_interne || 'Sans titre',
      Type: p.type || 'actu',
      Contenu: contenu,
      'Date Publication': prev.date_publication,
      'Heure Suggérée': p.heure_publication_suggeree || '',
      Statut: 'En attente de validation',
      'Source Actu': p.actu_source || '',
      'Date Génération': prev.date_generation,
      'Publié': false,
      image_titre: p.image_titre || '',
      image_sous_titre: p.image_sous_titre || '',
      image_icone: p.image_icone || ''
    }
  };
});

const items = $input.all();
const SIMILARITY_THRESHOLD = 0.85;
const results = [];

for (const item of items) {
  const d = item.json;
  const contenu = d.Contenu || '';

  if (d.Statut === 'Rejeté' || contenu.length < 50) {
    results.push({ json: { ...d, qdrant_status: 'skipped' } });
    continue;
  }

  try {
    const truncated = contenu.substring(0, 2000);
    const embResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-001:embedContent?key={{GEMINI_KEY}}',
      headers: { 'Content-Type': 'application/json' },
      body: {
        model: 'models/gemini-embedding-001',
        content: { parts: [{ text: truncated }] }
      },
      json: true
    });

    const embedding = embResponse.embedding?.values || [];
    if (embedding.length === 0) {
      results.push({ json: { ...d, qdrant_status: 'no_embedding' } });
      continue;
    }

    const searchResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://qdrant:6333/collections/linkedin_posts/points/search',
      headers: { 'Content-Type': 'application/json' },
      body: {
        vector: embedding,
        limit: 3,
        with_payload: { include: ['hook', 'type', 'sentAt', 'text_length'] }
      },
      json: true
    });

    const matches = searchResponse.result || [];
    const topScore = matches.length > 0 ? matches[0].score : 0;
    const topMatch = matches.length > 0 ? matches[0].payload : null;

    if (topScore > SIMILARITY_THRESHOLD) {
      results.push({ json: {
        ...d,
        Statut: 'Doublon détecté',
        qdrant_status: 'duplicate',
        qdrant_score: Math.round(topScore * 1000) / 1000,
        qdrant_similar_hook: topMatch?.hook || '',
        qdrant_similar_date: topMatch?.sentAt || ''
      }});
    } else {
      results.push({ json: {
        ...d,
        qdrant_status: 'original',
        qdrant_score: Math.round(topScore * 1000) / 1000,
        qdrant_similar_hook: topMatch?.hook || 'aucun match'
      }});
    }
  } catch (e) {
    results.push({ json: { ...d, qdrant_status: 'error: ' + e.message } });
  }
}

return results;

const items = $input.all();
const item = items[0];
const binaryKey = Object.keys(item.binary)[0];
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const templateBase64 = buffer.toString('base64');
