  body: { expression: 'folder:moi AND resource_type:image', max_results: 30 }, json: true
});

const photos = searchResponse.resources || [];
if (photos.length === 0) {
  const prompt = `Edit this image: replace the dark navy pill text with: ${imageTitre}. Replace subtitle with: ${imageSousTitre}. Keep everything else identical.`;
  return [{json:{requestBody:{contents:[{parts:[{inline_data:{mime_type:templateMime,data:templateBase64}},{text:prompt}]}],generationConfig:{responseModalities:["TEXT","IMAGE"]}}}}];
}

const randomPhoto = photos[Math.floor(Math.random() * photos.length)];
const photoUrl = randomPhoto.secure_url || randomPhoto.url;
const photoBuffer = await this.helpers.httpRequest({ method: 'GET', url: photoUrl, encoding: 'arraybuffer', returnFullResponse: false, json: false });
const photoBase64 = Buffer.from(photoBuffer, 'binary').toString('base64');
const isValidPng = photoBase64.startsWith('iVBOR');
const finalPhotoMime = isValidPng ? 'image/png' : 'image/jpeg';

const prompt = `I'm giving you TWO images:
- IMAGE 1: a design template
- IMAGE 2: a photo of a person named Enzo

Generate a NEW image that is an EXACT COPY of IMAGE 1 with ONLY these 2 modifications:

MODIFICATION 1: The top half of IMAGE 1 contains a photo. Replace that photo with IMAGE 2 (Enzo's photo). Place IMAGE 2 in the same area. Keep the original aspect ratio of IMAGE 2 — do NOT stretch or distort. Center and crop if needed, but never change the proportions of the person's face or body.

MODIFICATION 2: In the bottom half, replace ALL text with ONLY these 2 elements (nothing else):

1. (inside the dark navy rounded pill/badge, bold white text): ${imageTitre}
2. (smaller gray text below the badge): ${imageSousTitre}

These 2 text elements must be centered and stacked vertically. Remove ALL other text from the bottom half except "Enzo Quelenis" near the avatar.

EVERYTHING ELSE must be an IDENTICAL COPY of IMAGE 1:
- The bottom area with the small circular photo of Enzo and "Enzo Quelenis" text - COPY EXACTLY
- The light blue/white gradient background - COPY EXACTLY
- Do NOT add any logo, watermark, or branding that is not in IMAGE 1

Output the same dimensions as IMAGE 1.`;

return [{json:{requestBody:{contents:[{parts:[
  {inline_data:{mime_type:templateMime, data:templateBase64}},
  {inline_data:{mime_type:finalPhotoMime, data:photoBase64}},
  {text:prompt}
]}],generationConfig:{responseModalities:["TEXT","IMAGE"]}}}}];

