1. REPLACE the bold white text inside the dark navy blue pill/badge in the center. The text must be: ${imageTitre}

2. REPLACE the subtitle text below the badge. The text must be: ${imageSousTitre}

Remove any other text that is not part of the original template layout. Do NOT modify anything else. Output same dimensions.`;

return [{json:{requestBody:{contents:[{parts:[{inline_data:{mime_type:mimeType,data:imageBase64}},{text:prompt}]}],generationConfig:{responseModalities:["TEXT","IMAGE"]}}}}];

const response = $input.first().json;
let imageBase64 = ''; let mimeType = 'image/png';
try {
  for (const candidate of (response.candidates||[])) {
    for (const part of (candidate.content?.parts||[])) {
      const inlineData = part.inline_data || part.inlineData;
