    }
    if (imageBase64) break;
  }
} catch (e) { return [{json:{error:'Erreur parsing Gemini: '+e.message}}]; }
if (!imageBase64) return [{json:{error:'Gemini n\'a pas retourné d\'image (politique)'}}];
const buf = Buffer.from(imageBase64, 'base64');
const ext = mimeType.includes('png') ? 'png' : 'jpg';
