} catch (e) { return [{json:{error:'Erreur parsing Gemini: '+e.message}}]; }
if (!imageBase64) return [{json:{error:'Gemini n\'a pas retourné d\'image (tech)'}}];
const buf = Buffer.from(imageBase64, 'base64');
const ext = mimeType.includes('png') ? 'png' : 'jpg';
const bd = await this.helpers.prepareBinaryData(buf, `milleweb-tech-${new Date().toISOString().split('T')[0]}.${ext}`, mimeType);
return [{json:{}, binary:{data:bd}}];

// Analyser les top posts pour extraire les patterns viraux
const prevData = $input.first().json;

try {
  // 1. Récupérer TOUS les posts depuis Qdrant avec leurs métriques
  const scrollResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://qdrant:6333/collections/linkedin_posts/points/scroll',
    headers: { 'Content-Type': 'application/json' },
    body: {
      limit: 100,
      with_payload: true,
      with_vector: false
    },
    json: true
  });

  const points = scrollResponse.result?.points || [];

  if (points.length < 5) {
    return [{ json: { ...prevData, top_posts_analysis: 'Pas assez de posts pour analyser (min 5)', viral_patterns: '' } }];
  }

  // 2. Trier par score composite de viralité
  const sorted = points
    .filter(p => p.payload && p.payload.text && p.payload.text.length > 100)
    .sort((a, b) => {
      const scoreA = (a.payload.engagementRate || 0) * 0.4 + 
                     (a.payload.reactions || 0) * 0.3 + 
                     (a.payload.comments || 0) * 0.2 + 
                     ((a.payload.impressions || 0) / 100) * 0.1;
      const scoreB = (b.payload.engagementRate || 0) * 0.4 + 
                     (b.payload.reactions || 0) * 0.3 + 
                     (b.payload.comments || 0) * 0.2 + 
                     ((b.payload.impressions || 0) / 100) * 0.1;
      return scoreB - scoreA;
    });

  // 3. Top 5 et Bottom 5
  const top5 = sorted.slice(0, 5);
  const bottom5 = sorted.slice(-5).reverse();

  // 4. Extraire les patterns
  const topLengths = top5.map(p => p.payload.text_length || p.payload.text.length);
  const avgTopLength = Math.round(topLengths.reduce((a, b) => a + b, 0) / topLengths.length);

  const allEngagement = sorted.map(p => p.payload.engagementRate || 0);
  const avgEngagement = (allEngagement.reduce((a, b) => a + b, 0) / allEngagement.length).toFixed(2);

  const typePerf = {};
  sorted.forEach(p => {
    const t = p.payload.type || 'perso';
    if (!typePerf[t]) typePerf[t] = { total: 0, count: 0, reactions: 0, impressions: 0 };
    typePerf[t].total += p.payload.engagementRate || 0;
    typePerf[t].count++;
    typePerf[t].reactions += p.payload.reactions || 0;
    typePerf[t].impressions += p.payload.impressions || 0;
  });

  const typePerfSummary = Object.entries(typePerf).map(([type, data]) => 
    type + ': ' + (data.total / data.count).toFixed(2) + '% eng moyen, ' + Math.round(data.reactions / data.count) + ' reactions/post, ' + Math.round(data.impressions / data.count) + ' impressions/post'
  ).join(' | ');

  // 5. Construire le briefing
  const analysis = 'ANALYSE DE TES ' + sorted.length + ' POSTS LINKEDIN :\n\n' +
    'PERFORMANCE MOYENNE : ' + avgEngagement + '% engagement rate\n\n' +
    'TOP 5 POSTS (les plus viraux) :\n' +
    top5.map((p, i) => {
      const d = p.payload;
      return (i + 1) + '. [' + d.engagementRate + '% eng, ' + d.reactions + ' reactions, ' + d.comments + ' comments, ' + d.impressions + ' impressions]\n   Hook: "' + (d.hook || d.text.split('\n')[0]) + '"\n   Type: ' + d.type + ' | Longueur: ' + (d.text_length || d.text.length) + ' chars';
    }).join('\n') + '\n\n' +
    'BOTTOM 5 (les moins performants) :\n' +
    bottom5.map((p, i) => {
      const d = p.payload;
      return (i + 1) + '. [' + d.engagementRate + '% eng, ' + d.reactions + ' reactions] Hook: "' + (d.hook || d.text.split('\n')[0]) + '"';
    }).join('\n') + '\n\n' +
    'PATTERNS IDENTIFIES :\n' +
    '- Longueur ideale : ~' + avgTopLength + ' caracteres (tes top posts)\n' +
    '- Performance par type : ' + typePerfSummary + '\n' +
    '- Les hooks courts, provocateurs et personnels performent le mieux\n' +
    '- Les posts avec du vecu et des histoires personnelles battent les posts purement informatifs';

  return [{ json: { ...prevData, top_posts_analysis: analysis } }];

} catch (e) {
  return [{ json: { ...prevData, top_posts_analysis: 'Analyse indisponible: ' + e.message } }];
}

// Régénérer un post détecté comme doublon (max 2 tentatives)
const d = $input.first().json;
const MAX_RETRIES = 2;
const SIMILARITY_THRESHOLD = 0.85;

// Récupérer les actus originales depuis le node Parser
let actus;
try {
  actus = $('📊 Parser les actus').first().json;
} catch(e) {
  actus = { politique: [], tech: [] };
}

// Récupérer l'analyse des top posts
let topAnalysis = '';
try {
  topAnalysis = $('📊 Analyser top posts').first().json.top_posts_analysis || '';
} catch(e) {}

const postType = d.Type || 'actu';
const similarHook = d.qdrant_similar_hook || '';
const similarDate = d.qdrant_similar_date || '';
const originalContenu = d.Contenu || '';

let lastPost = null;
let success = false;

for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  try {
    // 1. Appeler Gemini pour régénérer
    const prompt = `Tu es un ghostwriter LinkedIn expert. Tu dois RÉGÉNÉRER un post ${postType === 'actu' ? 'politique/actualité' : 'tech/informatique'} car le précédent était trop similaire à un post déjà publié.

POST REJETÉ (trop similaire) :
"${originalContenu.substring(0, 500)}"

POST EXISTANT SIMILAIRE (à ÉVITER absolument) :
Hook: "${similarHook}"
Date: ${similarDate}

ACTUALITÉS DISPONIBLES :
${postType === 'actu' ? JSON.stringify(actus.politique || []) : JSON.stringify(actus.tech || [])}

${topAnalysis ? 'ANALYSE PERFORMANCE :\n' + topAnalysis.substring(0, 1000) : ''}

INSTRUCTIONS :
- Choisis une AUTRE actualité ou un AUTRE ANGLE sur le même sujet
- Le hook doit être COMPLÈTEMENT DIFFÉRENT du post rejeté et du post existant
- Garde le même ton (cash, provocateur, personnel) et le même format (800-1500 chars)
- Tentative ${attempt}/${MAX_RETRIES} — sois créatif et original !

RETOURNE UNIQUEMENT un JSON :
{"type":"${postType}","titre_interne":"","contenu":"HOOK\\n\\n\\nCorps...","hashtags":"#tag1 #tag2","actu_source":"","heure_publication_suggeree":"","image_titre":"TITRE MAX 5 MOTS","image_sous_titre":"Sous-titre max 8 mots","image_icone":"description icône flat design"}`;

    const geminiResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent?key={{GEMINI_KEY}}',
      headers: { 'Content-Type': 'application/json' },
      body: {
        contents: [{ parts: [{ text: prompt }] }],
        generationConfig: { maxOutputTokens: 4000, temperature: 1.0 }
      },
      json: true
    });

    // 2. Parser la réponse
    let responseText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';

    // Nettoyer le JSON
    const mdMatch = responseText.match(/```json?\n?([\s\S]*?)\n?```/);
    if (mdMatch) responseText = mdMatch[1];

    // Parser caractère par caractère pour les \n
    let cleaned = '';
    let inString = false;
    let escaped = false;
    for (let i = 0; i < responseText.length; i++) {
      const ch = responseText[i];
      if (escaped) { cleaned += ch; escaped = false; continue; }
      if (ch === '\\') { escaped = true; cleaned += ch; continue; }
      if (ch === '"') { inString = !inString; cleaned += ch; continue; }
      if (inString && ch === '\n') { cleaned += '\\n'; continue; }
      if (inString && ch === '\r') { continue; }
      cleaned += ch;
    }

    const braceStart = cleaned.indexOf('{');
    const braceEnd = cleaned.lastIndexOf('}');
    if (braceStart === -1) throw new Error('Pas de JSON');

    const post = JSON.parse(cleaned.substring(braceStart, braceEnd + 1));

    let contenu = (post.contenu || '').replace(/\\n/g, '\n');
    const hashtags = post.hashtags || '';
    if (hashtags && !contenu.includes(hashtags)) {
      contenu = contenu + '\n\n' + hashtags;
    }

    // 3. Vérifier dans Qdrant
    const truncated = contenu.substring(0, 2000);
    const embResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-001:embedContent?key={{GEMINI_KEY}}',
      headers: { 'Content-Type': 'application/json' },
      body: { model: 'models/gemini-embedding-001', content: { parts: [{ text: truncated }] } },
      json: true
    });

    const embedding = embResponse.embedding?.values || [];
    if (embedding.length === 0) throw new Error('No embedding');

    const searchResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://qdrant:6333/collections/linkedin_posts/points/search',
      headers: { 'Content-Type': 'application/json' },
      body: { vector: embedding, limit: 3, with_payload: { include: ['hook', 'type', 'sentAt'] } },
      json: true
    });

    const matches = searchResponse.result || [];
    const topScore = matches.length > 0 ? matches[0].score : 0;

    if (topScore <= SIMILARITY_THRESHOLD) {
      // Post original — on le garde !
      lastPost = {
        Titre: post.titre_interne || 'Régénéré',
        Type: postType,
        Contenu: contenu,
        'Date Publication': d['Date Publication'],
        'Heure Suggérée': post.heure_publication_suggeree || '',
        Statut: 'En attente de validation',
        'Source Actu': post.actu_source || '',
        'Date Génération': d['Date Génération'],
        'Publié': false,
        image_titre: post.image_titre || '',
        image_sous_titre: post.image_sous_titre || '',
        image_icone: post.image_icone || '',
        qdrant_status: 'regenerated_ok',
        qdrant_score: Math.round(topScore * 1000) / 1000,
        regen_attempt: attempt
      };
      success = true;
      break;
    }

    // Encore doublon — retry avec plus de créativité
  } catch (e) {
    // Erreur — on continue à la tentative suivante
  }

  // Pause 1s entre les tentatives
  if (attempt < MAX_RETRIES) {
    await new Promise(r => setTimeout(r, 1000));
  }
}

if (success && lastPost) {
  return [{ json: lastPost }];
} else {
  // Échec après toutes les tentatives — rejeter
  return [{ json: {
    ...d,
    Statut: 'Rejeté',
    qdrant_status: 'duplicate_after_regen',
    message: '⚠️ Post ' + postType + ' rejeté après ' + MAX_RETRIES + ' tentatives de régénération'
  }}];
}
